{
  "intent_summary": "Assess revenue dependency by measuring each campus region's contribution to total national Rytelo sales over the most recent 52 weeks of available data, and flag regions with high concentration.",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_52_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "region_sales_52w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "campus_region"
    },
    {
      "metric_name": "nation_sales_52w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date in the dataset to anchor the default 52-week window.",
      "logic": "Compute MAX(week_end_date) from data_867 and expose it as max_week_end_date."
    },
    {
      "name": "time_window_cte",
      "purpose": "Define the default analysis window and its boundaries.",
      "logic": "Set window_end_date = max_week_end_date; set window_start_date = window_end_date minus 51 weeks (inclusive 52-week span)."
    },
    {
      "name": "region_agg_cte",
      "purpose": "Aggregate 52-week sales by campus_region.",
      "logic": "Filter rows to [window_start_date, window_end_date] using week_end_date; group by campus_region; compute SUM(rytelo_total_mg) as region_sales_52w."
    },
    {
      "name": "nation_agg_cte",
      "purpose": "Aggregate 52-week national sales across all regions for denominator.",
      "logic": "Filter rows to [window_start_date, window_end_date] using week_end_date; compute SUM(rytelo_total_mg) as nation_sales_52w."
    },
    {
      "name": "contribution_cte",
      "purpose": "Compute each region's contribution percent of national sales and concentration ranking.",
      "logic": "Join region_agg_cte to nation_agg_cte (cross join); compute region_contribution_52w = (region_sales_52w / nation_sales_52w) * 100; compute region_rank by region_sales_52w descending."
    },
    {
      "name": "concentration_summary_cte",
      "purpose": "Provide overall concentration indicators to determine dependency on a few regions.",
      "logic": "From contribution_cte compute top_1_region_contribution_52w as contribution of rank=1; top_2_regions_contribution_52w as sum of contributions for ranks<=2; top_3_regions_contribution_52w as sum of contributions for ranks<=3."
    }
  ],
  "group_by": ["campus_region"],
  "order_by": [
    {
      "column": "region_sales_52w",
      "direction": "DESC"
    }
  ],
  "limit": 10,
  "final_output": {
    "columns": [
      "window_start_date",
      "window_end_date",
      "campus_region",
      "region_sales_52w",
      "nation_sales_52w",
      "region_contribution_52w%",
      "region_rank",
      "top_1_region_contribution_52w%",
      "top_2_regions_contribution_52w%",
      "top_3_regions_contribution_52w%"
    ],
    "row_granularity": "per_group"
  },
  "validation_rules": [
    "Use data_867 as the only source table for this question.",
    "Use rytelo_total_mg (not rytelo_total_sls) because the question is about Rytelo revenue dependency without explicit market share or competitor comparison request.",
    "Default time window is the most recent 52 weeks of available data when the user does not specify a period.",
    "Derive max_week_end_date using MAX(week_end_date); do not use system date; do not use MAX(month_year) or MAX(quarter_year).",
    "Output must explicitly include window_start_date and window_end_date.",
    "Region contribution must use national total (all rows in the window) as denominator and must be expressed with a trailing '%'.",
    "Also include the corresponding absolute sales values alongside contribution metrics (region_sales_52w and nation_sales_52w).",
    "Order regions by region_sales_52w descending to highlight concentration; limit output to top 10 regions.",
    "All computations related to percentage values must be reported as integers (no decimals) before output, and include the '%' symbol in the label."
  ]
}

{
  "intent_summary": "Assess breadth of Rytelo distribution/coverage by counting active campus accounts (rytel_total_mg > 0) and total shipped volume over the most recent 52 weeks of available data, at the national level (no campus grouping).",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "week_end_date",
      "operator": ">=",
      "value": "derived:rolling_window_52_weeks_from_max_week_end_date"
    },
    {
      "column": "week_end_date",
      "operator": "<=",
      "value": "derived:max_week_end_date"
    }
  ],
  "aggregations": [
    {
      "metric_name": "active_campus_accounts_52w",
      "function": "COUNT",
      "column": "campus_id",
      "group_level": "none"
    },
    {
      "metric_name": "sales_mg_52w",
      "function": "SUM",
      "column": "rytelo_total_mg",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date available in data_867 to anchor rolling windows.",
      "logic": "Compute MAX(week_end_date) from data_867 and expose as max_week_end_date."
    },
    {
      "name": "active_accounts_filter_logic",
      "purpose": "Ensure breadth/account status metrics consider only records with positive Rytelo volume.",
      "logic": "For active campus account counting, include only rows where rytelo_total_mg > 0; count distinct campus_id after applying the 52-week date window."
    },
    {
      "name": "rolling_52w_window_bounds",
      "purpose": "Define explicit start and end boundaries for the last 52 weeks based on max_week_end_date.",
      "logic": "Set window_end_date = max_week_end_date; set window_start_date = (max_week_end_date - 51 weeks) aligned to week_end_date-based weeks."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "window_start_date_52w",
      "window_end_date_52w",
      "active_campus_accounts_52w",
      "sales_mg_52w"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Default time period to the most recent 52 weeks when user does not specify a time window.",
    "Determine the latest available period using MAX(week_end_date); do not use system date.",
    "Breadth/account ordering status metrics must consider only records where rytelo_total_mg > 0 and must count DISTINCT campus_id.",
    "Use data_867 and rytelo_total_mg (not rytelo_total_sls) because the question is not about market share or competitor comparisons.",
    "Because the request is not explicitly campus-level output, do not group by campus_id or campus_account_name; return a national single-row summary.",
    "Output must explicitly include the time window boundaries (start and end dates) for the 52-week period."
  ]
}

{
  "intent_summary": "Assess performance in adding new campus (child) businesses by counting newly active campus_ids in the most recent 13 weeks versus the prior 13 weeks, including absolute counts and growth percent, using only accounts with Rytelo activity (rytelo_total_mg > 0).",
  "tables": ["data_867"],
  "filters": [
    {
      "column": "rytelo_total_mg",
      "operator": ">",
      "value": 0
    }
  ],
  "aggregations": [
    {
      "metric_name": "new_business_accounts_r13w",
      "function": "COUNT",
      "column": "campus_id",
      "group_level": "none"
    },
    {
      "metric_name": "new_business_accounts_p13w",
      "function": "COUNT",
      "column": "campus_id",
      "group_level": "none"
    }
  ],
  "subqueries": [
    {
      "name": "max_week_end_date_cte",
      "purpose": "Identify the most recent week_end_date available in data_867 to anchor rolling windows.",
      "logic": "Compute MAX(week_end_date) from data_867."
    },
    {
      "name": "campus_first_active_week_cte",
      "purpose": "Determine when each campus_id first became active (first week with rytelo_total_mg > 0).",
      "logic": "From data_867 filtered to rytelo_total_mg > 0, group by campus_id and compute MIN(week_end_date) as first_active_week_end_date."
    },
    {
      "name": "rolling_windows_cte",
      "purpose": "Define R13W and P13W time boundaries based on max_week_end_date.",
      "logic": "Using max_week_end_date, define R13W as the 13 week_end_date values ending at max_week_end_date (inclusive) and P13W as the immediately preceding 13 week_end_date values."
    },
    {
      "name": "new_business_counts_cte",
      "purpose": "Count distinct new campus businesses in R13W and P13W based on first_active_week_end_date.",
      "logic": "Join campus_first_active_week_cte to rolling_windows_cte and count DISTINCT campus_id where first_active_week_end_date falls within R13W for new_business_accounts_r13w and within P13W for new_business_accounts_p13w."
    },
    {
      "name": "growth_calc_cte",
      "purpose": "Compute growth percent for new businesses from P13W to R13W and include required time boundaries.",
      "logic": "Compute growth_new_business_r13w_vs_p13w_pct = CASE WHEN new_business_accounts_p13w = 0 AND new_business_accounts_r13w > 0 THEN 100 WHEN new_business_accounts_p13w = 0 AND new_business_accounts_r13w = 0 THEN 0 ELSE ((new_business_accounts_r13w - new_business_accounts_p13w) / new_business_accounts_p13w) * 100 END; convert to integer before output; also output r13w_start_week_end_date, r13w_end_week_end_date, p13w_start_week_end_date, p13w_end_week_end_date from rolling_windows_cte."
    }
  ],
  "group_by": [],
  "order_by": [],
  "limit": null,
  "final_output": {
    "columns": [
      "p13w_start_week_end_date",
      "p13w_end_week_end_date",
      "new_business_accounts_p13w",
      "r13w_start_week_end_date",
      "r13w_end_week_end_date",
      "new_business_accounts_r13w",
      "growth_new_business_r13w_vs_p13w_pct"
    ],
    "row_granularity": "single_row"
  },
  "validation_rules": [
    "Default growth timeframe when unspecified: R13W vs P13W.",
    "All account ordering status metrics (new/active/total accounts) must consider only records with rytelo_total_mg > 0.",
    "Campus-level is the default; do not roll up to parent entities.",
    "Determine max date using MAX(week_end_date) and do not use system date.",
    "Rolling windows must be anchored to max_week_end_date and defined as consecutive week_end_date buckets.",
    "Output must explicitly include time period boundaries (start and end week_end_date for both R13W and P13W).",
    "Growth must be expressed as a percentage with a '%' appended in presentation, and must be converted to an integer (no decimals) before reporting.",
    "If previous period value is 0 and current period value > 0, growth must be reported as 100%.",
    "Always accompany the growth metric with the corresponding absolute counts for both periods."
  ]
}
